```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test resetting a calculation node with new dependencies
 *
 * @param a First input value
 * @param b Second input value
 * @param c Third input value
 * @return int The result after resetting calculation to use different dependencies
 */
int test_calculation_reset(int a, int b, int c) {
    // Step 1: Create reactive variables
    auto var_a = reaction::Var<int>(a);
    auto var_b = reaction::Var<int>(b);
    auto var_c = reaction::Var<int>(c);

    // Step 2: Create initial calculation (a + b)
    auto calc = reaction::make_binary_expr<reaction::AddOp>(var_a, var_b);

    // Step 3: Reset calculation with different dependencies (b + c)
    // In the reaction library, we can reassign the calculation expression
    calc = reaction::make_binary_expr<reaction::AddOp>(var_b, var_c);

    // Step 4: Return result after reset
    return calc();
}

}  // namespace test_reaction
```

